21	const NetworkMapActionsKebabDropdown: FC<NetworkMapActionsDropdownProps> = ({ data, isKebab }) => {
22	  const { t } = useForkliftTranslation();
23	
24	  const [isOpen, setIsOpen] = useState(false);
25	
26	  const onToggleClick = () => {
27	    setIsOpen((value) => !value);
28	  };
29	
