38	      onOpenChange={(value: boolean) => {
39	        setIsOpen(value);
40	      }}
41	      onSelect={onSelect}
42	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
43	        <MenuToggle
44	          ref={toggleRef}
45	          onClick={onToggleClick}
46	          isExpanded={isOpen}
47	          variant={isKebab ? 'plain' : 'default'}
48	        >
49	          {isKebab ? <EllipsisVIcon /> : t('Actions')}
50	        </MenuToggle>
51	      )}
52	      shouldFocusToggleOnSelect
53	      popperProps={{
54	        position: 'right',
55	      }}
56	    >
57	      <DropdownList>
58	        <NetworkMapActionsDropdownItems data={data} />
59	      </DropdownList>
60	    </Dropdown>
61	  );
62	};
63	
64	export const NetworkMapActionsDropdown: FC<NetworkMapActionsDropdownProps> = (props) => (
65	  <ModalHOC>
66	    <Flex flex={{ default: 'flex_3' }} flexWrap={{ default: 'nowrap' }}>
67	      <FlexItem grow={{ default: 'grow' }} />
68	      <FlexItem align={{ default: 'alignRight' }}>
69	        <NetworkMapActionsKebabDropdown {...props} />
70	      </FlexItem>
71	    </Flex>
72	  </ModalHOC>
73	);
74	
75	type NetworkMapActionsDropdownProps = {
76	  isKebab?: boolean;
77	} & CellProps;

